const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const LoginScreen = ({ onLogin, admins }: { onLogin: (u: User) => void, admins: User[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw account voor toegang.</p>

                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid #ddd' }}
                    >
                        {admins.map(a => (
                            <option key={a.id} value={a.id}>{a.name} ({a.dienst})</option>
                        ))}
                    </select>
                </div>

                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met aanmelden...' : 'Aanmelden'}
                </button>
                <div className="login-footer">
                    &copy; 2024 Uw Organisatie
                </div>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-bar-container">
        <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true }: { task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean }) => (
    <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit ? 'read-only' : ''}`}>
        <div className="task-header">
            <div className="task-main">
                {!isTemplate && (
                    <input 
                        type="checkbox" 
                        checked={task.isCompleted} 
                        onChange={() => onToggle(task.id)} 
                        disabled={!canEdit}
                    />
                )}
                <div className="task-content">
                    <h3>{task.title}</h3>
                    {task.description && <p>{task.description}</p>}
                </div>
            </div>
            {isTemplate && canEdit && (
                <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>
            )}
        </div>
        <div className="task-footer">
            <div className="tags">
                <span className="tag dienst">{task.dienst}</span>
                <span className="tag category">{task.category}</span>
            </div>
            {task.isCompleted && (
                <div className="completion-info">
                    Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}
                </div>
            )}
        </div>
    </div>
);

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v3_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            templateTasks: INITIAL_TASKS,
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS,
            employees: [],
            admins: [
                { id: '1', name: 'IT Admin', email: 'it@org.be', role: 'SuperUser', dienst: 'IT' },
                { id: '2', name: 'LIK Admin', email: 'lik@org.be', role: 'Admin', dienst: 'LIK' },
                { id: '3', name: 'Logistiek Admin', email: 'log@org.be', role: 'Admin', dienst: 'Logistiek' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienst: 'All',
            filterCategory: 'All'
        };
    });

    const [isAddModalOpen, setIsAddModalOpen] = useState(false);
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v3_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienst: 'All' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        const filteredByStatus = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        if (state.user.dienst === 'IT') return filteredByStatus;
        return filteredByStatus.filter(e => e.department === state.user?.dienst);
    }, [state.employees, state.user, state.view]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;
        return currentTasks.filter(t => {
            const isDeptAllowed = state.user?.dienst === 'IT' || t.dienst === state.user?.dienst;
            if (!isDeptAllowed) return false;
            const dienstMatch = state.filterDienst === 'All' || t.dienst === state.filterDienst;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            return dienstMatch && catMatch;
        });
    }, [selectedEmployee, state.filterDienst, state.filterCategory, state.user]);

    // Actions
    const createEmployee = (name: string, department: string) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            department,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status: 'onboarding',
            tasks: state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })),
            offboardingTasks: []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: 'employees' }));
        setIsAddModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, department: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, department } : e)
        }));
        setEditingEmployee(null);
    };

    const startOffboarding = (id: string) => {
        if (window.confirm("Deze medewerker verplaatsen naar Offboarding?")) {
            setState(prev => ({
                ...prev,
                employees: prev.employees.map(e => {
                    if (e.id === id) {
                        return {
                            ...e,
                            status: 'offboarding',
                            offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                        };
                    }
                    return e;
                })
            }));
        }
    };

    const deleteEmployee = (id: string) => {
        if (window.confirm("Medewerker definitief verwijderen?")) {
            setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
        }
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId) return;
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(emp => {
                if (emp.id === prev.selectedEmployeeId) {
                    const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
                    return {
                        ...emp,
                        [taskType]: emp[taskType].map(t => {
                            if (t.id === taskId) {
                                const nextStatus = !t.isCompleted;
                                return {
                                    ...t,
                                    isCompleted: nextStatus,
                                    completedBy: nextStatus ? prev.user?.name : undefined,
                                    completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                };
                            }
                            return t;
                        })
                    };
                }
                return emp;
            })
        }));
    };

    const addAdmin = (name: string, email: string, dienst: Dienst) => {
        const newAdmin: User = { id: generateId(), name, email, role: 'Admin', dienst };
        setState(prev => ({ ...prev, admins: [...prev.admins, newAdmin] }));
        setIsAddAdminModalOpen(false);
    };

    const deleteAdmin = (id: string) => {
        if (state.admins.length <= 1) return alert("Minimaal één beheerder vereist.");
        setState(prev => ({ ...prev, admins: prev.admins.filter(a => a.id !== id) }));
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} />;
    }

    return (
        <div className="app-container">
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null }))} 
                currentView={state.view} 
            />

            <main className="main-content">
                {/* Employee Overview (Onboarding / Offboarding) */}
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                {state.user.dienst === 'IT' && state.view === 'employees' && (
                                    <button className="primary-action-btn" onClick={() => setIsAddModalOpen(true)}>+ Nieuwe Medewerker</button>
                                )}
                            </div>
                            <p>Totaal aantal medewerkers in deze fase: {accessibleEmployees.length}</p>
                        </header>

                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th>
                                        <th>Dienst</th>
                                        <th>Datum</th>
                                        <th>Voortgang</th>
                                        <th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const visibleTasks = currentTasks.filter(t => state.user!.dienst === 'IT' || t.dienst === state.user!.dienst);
                                        const completed = visibleTasks.filter(t => t.isCompleted).length;
                                        const total = visibleTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{emp.department}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)} title="Bewerken">✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)} title="Start Offboarding">Out</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => deleteEmployee(emp.id)} title="Verwijderen">🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Checklist View */}
                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug</button>
                        <header className="dashboard-header">
                            <h1>Checklist: {selectedEmployee.name} ({selectedEmployee.status})</h1>
                            <p>Beheer van taken voor {selectedEmployee.name}</p>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.map(task => (
                                <TaskCard key={task.id} task={task} onToggle={toggleEmployeeTask} canEdit={state.user!.dienst === 'IT' || task.dienst === state.user!.dienst} />
                            ))}
                        </div>
                    </div>
                )}

                {/* Admin Beheer */}
                {state.view === 'admin_beheer' && state.user.dienst === 'IT' && (
                    <div className="admin-beheer">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Beheer Administrators</h1>
                                <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th>
                                        <th>Email</th>
                                        <th>Dienst</th>
                                        <th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}>
                                            <td><strong>{a.name}</strong></td>
                                            <td>{a.email}</td>
                                            <td><span className="emp-dept-badge">{a.dienst}</span></td>
                                            <td style={{ textAlign: 'right' }}>
                                                <button className="icon-btn delete" onClick={() => deleteAdmin(a.id)}>🗑</button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Template Managers */}
                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding' : 'Offboarding'} Template</h1>
                        <p>Beheer de masterlijst voor {state.user.dienst}.</p>
                        {/* Task toevoegen en lijst vergelijkbaar met vorige versie... */}
                    </div>
                )}
            </main>

            {/* Modals */}
            <Modal isOpen={isAddModalOpen} onClose={() => setIsAddModalOpen(false)} title="Nieuwe Medewerker">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.empName.value, form.empDept.value);
                }}>
                    <div className="form-group"><label>Naam</label><input name="empName" required /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="empDept">
                            <option value="IT">IT</option><option value="Logistiek">Logistiek</option><option value="LIK">LIK</option>
                        </select>
                    </div>
                    <div className="modal-footer">
                        <button type="submit" className="primary-action-btn">Aanmaken</button>
                    </div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Admin">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    addAdmin(form.admName.value, form.admEmail.value, form.admDept.value);
                }}>
                    <div className="form-group"><label>Naam</label><input name="admName" required /></div>
                    <div className="form-group"><label>Email</label><input name="admEmail" type="email" required /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="admDept">
                            <option value="IT">IT</option><option value="Logistiek">Logistiek</option><option value="LIK">LIK</option>
                        </select>
                    </div>
                    <div className="modal-footer">
                        <button type="submit" className="primary-action-btn">Admin Toevoegen</button>
                    </div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Medewerker Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.empName.value, form.empDept.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="empName" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="empDept" defaultValue={editingEmployee.department}>
                                <option value="IT">IT</option><option value="Logistiek">Logistiek</option><option value="LIK">LIK</option>
                            </select>
                        </div>
                        <div className="modal-footer">
                            <button type="submit" className="primary-action-btn">Opslaan</button>
                        </div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

