    --primary-dark: #0078d4;
    --bg: #111111;
    --surface: #1e1e1e;
    --text: #f5f5f5;
    --text-muted: #a1a1a1;
    --border: #333333;
    --shadow: 0 8px 16px rgba(0,0,0,0.4);
    --input-bg: #2d2d2d;
}

body {
    margin: 0;
    font-family: var(--font-sans);
    background-color: var(--bg);
    color: var(--text);
    transition: background-color 0.2s, color 0.2s;
}

/* --- Theme Toggle --- */
.theme-toggle {
    background: none;
    border: 1px solid var(--border);
    border-radius: 50%;
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: 16px;
    color: var(--text);
}

.theme-toggle:hover {
    background: var(--bg);
}

/* --- Login Screen --- */
.login-page {
    height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    background: linear-gradient(135deg, #0078d4 0%, #00188f 100%);
}

.login-card {
    background: var(--surface);
    padding: 40px;
    border-radius: 4px;
    width: 100%;
    max-width: 400px;
    box-shadow: 0 20px 40px rgba(0,0,0,0.2);
    text-align: center;
}

.microsoft-logo {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 2px;
    width: 40px;
    height: 40px;
    margin: 0 auto 20px;
}

.square { width: 19px; height: 19px; }
.red { background: #f25022; }
.green { background: #7fbb00; }
.blue { background: #00a1f1; }
.yellow { background: #ffbb00; }

.sso-button {
    width: 100%;
    padding: 12px;
    background: #2b2b2b;
    color: white;
    border: none;
    font-size: 16px;
    font-weight: 600;
    cursor: pointer;
    margin-top: 20px;
    transition: background 0.2s;
    border-radius: 4px;
}

.sso-button:hover { background: #000; }

/* --- App Layout --- */
.app-container {
    display: flex;
    flex-direction: column;
    height: 100vh;
}

.nav-container {
    height: 60px;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    padding: 0 24px;
    gap: 20px;
}

.nav-logo {
    display: flex;
    align-items: center;
    gap: 12px;
    font-weight: 700;
    color: var(--primary);
    margin-right: 20px;
}

.logo-icon {
    background: var(--primary);
    color: white;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 4px;
}

.nav-links {
    display: flex;
    gap: 4px;
    align-items: center;
}

.nav-links button {
    background: none;
    border: none;
    padding: 8px 16px;
    font-size: 14px;
    font-weight: 500;
    color: var(--text-muted);
    cursor: pointer;
    border-radius: 4px;
}

.nav-links button.active {
    background: var(--bg);
    color: var(--primary);
    font-weight: 600;
}

/* --- Dropdown --- */
.nav-dropdown {
    position: relative;
    display: inline-block;
}

.dropdown-content {
    display: none;
    position: absolute;
    background-color: var(--surface);
    min-width: 180px;
    box-shadow: var(--shadow);
    z-index: 10;
    border-radius: 4px;
    border: 1px solid var(--border);
    top: 100%;
}

.dropdown-content button {
    color: var(--text);
    padding: 12px 16px;
    text-decoration: none;
    display: block;
    width: 100%;
    text-align: left;
    border: none;
    background: none;
    font-size: 14px;
    border-radius: 0;
}

.dropdown-content button:hover {
    background-color: var(--bg);
}

.nav-dropdown:hover .dropdown-content {
    display: block;
}

.nav-user {
    margin-left: auto;
    display: flex;
    align-items: center;
    gap: 16px;
}

.user-info {
    display: flex;
    flex-direction: column;
    align-items: flex-end;
}

.user-name { font-weight: 600; font-size: 14px; color: var(--text); }
.user-dept { font-size: 12px; color: var(--primary); font-weight: 600; }

.logout-btn {
    background: none;
    border: 1px solid var(--border);
    padding: 6px 12px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 12px;
    color: var(--text);
}

/* --- Main Content --- */
.main-content {
    flex: 1;
    overflow-y: auto;
    padding: 40px 24px;
}

.dashboard-header {
    margin-bottom: 32px;
}

.header-flex {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 8px;
}

.header-flex h1 { margin: 0; font-size: 28px; color: var(--text); }

.primary-action-btn {
    background: var(--primary);
    color: white;
    border: none;
    padding: 10px 20px;
    border-radius: 4px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s;
}

.primary-action-btn:hover { background: var(--primary-dark); }

.secondary-btn {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    padding: 10px 20px;
    border-radius: 4px;
    font-weight: 600;
    cursor: pointer;
}

.back-link {
    background: none;
    border: none;
    color: var(--primary);
    cursor: pointer;
    padding: 0;
    margin-bottom: 20px;
    font-weight: 600;
}

/* --- Table View --- */
.employee-list-container {
    background: var(--surface);
    border-radius: 8px;
    box-shadow: var(--shadow);
    overflow: hidden;
    border: 1px solid var(--border);
}

.employee-table {
    width: 100%;
    border-collapse: collapse;
    text-align: left;
}

.employee-table th {
    background: var(--surface);
    padding: 12px 16px;
    font-size: 12px;
    font-weight: 600;
    color: var(--text-muted);
    text-transform: uppercase;
    border-bottom: 1px solid var(--border);
}

.employee-table td {
    padding: 14px 16px;
    border-bottom: 1px solid var(--border);
    font-size: 14px;
    color: var(--text);
}

.employee-row {
    cursor: pointer;
    transition: background 0.15s;
}

.employee-row:hover {
    background: var(--bg);
}

.emp-name-cell {
    font-weight: 600;
    color: var(--text);
}

.emp-dept-badge {
    background: var(--bg);
    color: var(--primary);
    padding: 2px 8px;
    border-radius: 4px;
    font-size: 11px;
    font-weight: 700;
}

/* --- Progress Bar --- */
.progress-cell {
    display: flex;
    align-items: center;
    gap: 12px;
    min-width: 180px;
}

.progress-bar-container {
    flex: 1;
    height: 8px;
    background: var(--border);
    border-radius: 4px;
    overflow: hidden;
}

.progress-bar-fill {
    height: 100%;
    background: var(--success);
    transition: width 0.3s ease;
}

.progress-text {
    font-size: 11px;
    font-weight: 600;
    color: var(--text-muted);
    min-width: 32px;
}

/* --- Icons & Actions --- */
.icon-btn {
    background: none;
    border: none;
    padding: 6px;
    cursor: pointer;
    border-radius: 4px;
    margin-left: 4px;
    color: var(--text-muted);
}

.icon-btn:hover { background: var(--bg); }
.icon-btn.edit:hover { color: var(--primary); }
.icon-btn.delete:hover { color: var(--danger); }

.icon-btn.offboard {
    background: #fff4ce;
    color: #8a662e;
    font-size: 11px;
    font-weight: 700;
    padding: 6px 12px;
    border-radius: 4px;
    display: inline-flex;
    align-items: center;
    border: 1px solid #fde7a9;
    margin-left: 8px;
}

.app-container.dark .icon-btn.offboard {
    background: #4a3717;
    color: #ffca7a;
    border-color: #5a4520;
}

.icon-btn.offboard:hover {
    background: #fde7a9;
}

/* --- Task Cards --- */
.task-grid {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.task-card {
    background: var(--surface);
    border-radius: 8px;
    border: 1px solid var(--border);
    padding: 20px;
}

.task-card.completed { border-left: 4px solid var(--success); }
.app-container.light .task-card.completed { background: #f8fff8; }
.app-container.dark .task-card.completed { background: #0a1f0a; }

.task-card.read-only { opacity: 0.7; background: var(--bg); }

.task-header { display: flex; justify-content: space-between; align-items: flex-start; }
.task-main { display: flex; gap: 16px; }
.task-main input[type="checkbox"] { width: 20px; height: 20px; cursor: pointer; }
.task-content h3 { margin: 0 0 4px; font-size: 16px; font-weight: 600; color: var(--text); }
.task-content p { margin: 0; font-size: 14px; color: var(--text-muted); }

.task-footer {
    margin-top: 16px;
    padding-top: 16px;
    border-top: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.tags { display: flex; gap: 8px; }
.tag { font-size: 11px; text-transform: uppercase; font-weight: 700; padding: 2px 8px; border-radius: 12px; }
.tag.dienst { background: var(--bg); color: var(--text); }
.tag.category { background: var(--bg); color: var(--primary); }

.delete-btn { color: var(--danger); background: none; border: none; font-size: 13px; cursor: pointer; font-weight: 600; }

/* --- Modals --- */
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.6);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    backdrop-filter: blur(2px);
}

.modal-content {
    background: var(--surface);
    width: 100%;
    max-width: 450px;
    border-radius: 8px;
    box-shadow: var(--shadow);
    overflow: hidden;
    color: var(--text);
}

.modal-header {
    padding: 16px 24px;
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.modal-header h2 { margin: 0; font-size: 18px; }

.modal-body { padding: 24px; }

.close-x {
    background: none;
    border: none;
    font-size: 24px;
    cursor: pointer;
    color: var(--text-muted);
}

.form-group { margin-bottom: 20px; }
.form-group label { display: block; font-weight: 600; margin-bottom: 8px; font-size: 14px; }
.form-group input, .form-group select {
    width: 100%; padding: 10px; border: 1px solid var(--border); border-radius: 4px; 
    background-color: var(--input-bg); color: var(--text); font-size: 14px;
}

.modal-footer { display: flex; justify-content: flex-end; gap: 12px; margin-top: 32px; }

/* --- Filters --- */
.filters {
    display: flex;
    gap: 24px;
    background: var(--surface);
    padding: 16px;
    border-radius: 8px;
    border: 1px solid var(--border);
    margin-top: 20px;
}

.filter-group { display: flex; align-items: center; gap: 12px; }
.filter-group label { font-weight: 600; font-size: 14px; }
.filter-group select {
    padding: 6px 12px; border: 1px solid var(--border); border-radius: 4px;
    background: var(--input-bg); color: var(--text);
}

.add-task-form {
    background: var(--surface);
    padding: 24px;
    border-radius: 8px;
    border: 1px solid var(--border);
    margin-bottom: 32px;
}

.form-row { display: flex; gap: 12px; margin-bottom: 12px; }
.form-row input, .form-row select { 
    flex: 1; padding: 10px; border: 1px solid var(--border); border-radius: 4px;
    background: var(--input-bg); color: var(--text);
}

@media (max-width: 768px) {
    .nav-container { padding: 0 12px; }
    .nav-logo .logo-text { display: none; }
    .header-flex { flex-direction: column; align-items: flex-start; gap: 12px; }
}

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'SuperUser'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[] 
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <h3>{task.title}</h3>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v5_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light'
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v5_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienstId: 'All' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        const filteredByStatus = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');
        if (state.user.role === 'SuperUser') return filteredByStatus;
        return filteredByStatus.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;
        return currentTasks.filter(t => {
            const isDeptAllowed = state.user?.role === 'SuperUser' || t.dienst === state.user?.dienstId;
            if (!isDeptAllowed) return false;
            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            return dienstMatch && catMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user]);

    // Actions
    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            tasks: status === 'onboarding' ? state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : [],
            offboardingTasks: status === 'offboarding' ? state.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding' }));
        setIsEmpModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, departmentId: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, departmentId } : e)
        }));
        setEditingEmployee(null);
    };

    const startOffboarding = (id: string) => {
        if (window.confirm("Deze medewerker verplaatsen naar Offboarding? De offboarding-taken worden geladen.")) {
            setState(prev => ({
                ...prev,
                employees: prev.employees.map(e => {
                    if (e.id === id) {
                        return {
                            ...e,
                            status: 'offboarding',
                            offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                        };
                    }
                    return e;
                })
            }));
        }
    };

    const addDepartment = (name: string) => {
        const newDept: Department = { id: generateId(), name };
        setState(prev => ({ ...prev, departments: [...prev.departments, newDept] }));
        setIsAddDeptModalOpen(false);
    };

    const deleteDepartment = (id: string) => {
        if (window.confirm("Weet u dit zeker?")) {
            setState(prev => ({ ...prev, departments: prev.departments.filter(d => d.id !== id) }));
        }
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId) return;
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(emp => {
                if (emp.id === prev.selectedEmployeeId) {
                    const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
                    return {
                        ...emp,
                        [taskType]: emp[taskType].map(t => {
                            if (t.id === taskId) {
                                const nextStatus = !t.isCompleted;
                                return {
                                    ...t,
                                    isCompleted: nextStatus,
                                    completedBy: nextStatus ? prev.user?.name : undefined,
                                    completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                };
                            }
                            return t;
                        })
                    };
                }
                return emp;
            })
        }));
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {/* Employee Lists */}
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                    + Nieuwe Medewerker
                                </button>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Dienst</th><th>Datum</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const visibleTasks = currentTasks.filter(t => state.user!.role === 'SuperUser' || t.dienst === state.user!.dienstId);
                                        const completed = visibleTasks.filter(t => t.isCompleted).length;
                                        const total = visibleTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)}>✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)}>Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== emp.id) }))}>🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Checklist View */}
                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug</button>
                        <header className="dashboard-header">
                            <h1>Checklist: {selectedEmployee.name}</h1>
                            <div className="filters">
                                <div className="filter-group">
                                    <label>Filter Dienst:</label>
                                    <select value={state.filterDienstId} onChange={(e) => setState(p => ({ ...p, filterDienstId: e.target.value }))}>
                                        <option value="All">Alle</option>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                </div>
                                <div className="filter-group">
                                    <label>Categorie:</label>
                                    <select value={state.filterCategory} onChange={(e) => setState(p => ({ ...p, filterCategory: e.target.value as any }))}>
                                        <option value="All">Alle</option>
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.map(task => (
                                <TaskCard key={task.id} task={task} onToggle={toggleEmployeeTask} departments={state.departments} />
                            ))}
                        </div>
                    </div>
                )}

                {/* Template Managers */}
                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template' : 'Offboarding Template'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const isOff = state.view === 'template_offboarding';
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false
                                };
                                setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: [...prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId" required>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                    <select name="cat">
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                    <button type="submit" className="primary-action-btn">Toevoegen</button>
                                </div>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => (
                                <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                    const isOff = state.view === 'template_offboarding';
                                    setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'].filter(t => t.id !== id) }));
                                }} departments={state.departments} />
                            ))}
                        </div>
                    </div>
                )}

                {/* Beheer Views (SuperUser only) */}
                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Diensten</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.departments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => deleteDepartment(d.id)}>🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Admins</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))}>🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            {/* Modals */}
            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker ${empModalStatus}`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.name.value, form.deptId.value, empModalStatus);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required autoFocus /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="deptId">
                            {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); addDepartment((e.target as any).name.value); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Admin">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rol</label>
                        <select name="role"><option value="Admin">Admin</option><option value="SuperUser">SuperUser (IT)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Medewerker Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.name.value, form.deptId.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="name" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="deptId" defaultValue={editingEmployee.departmentId}>{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                        </div>
                        <div className="modal-footer"><button type="submit" className="primary-action-btn">Opslaan</button></div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

export type Category = 'Account' | 'Software' | 'Hardware' | 'Toegang';
export type EmployeeStatus = 'onboarding' | 'offboarding';
export type Theme = 'light' | 'dark';

export interface Department {
    id: string;
    name: string;
}

export interface Task {
    id: string;
    title: string;
    description?: string;
    dienst: string; // Veranderd naar string voor dynamische koppeling
    category: Category;
    isCompleted: boolean;
    completedBy?: string;
    completedAt?: string;
}

export interface Employee {
    id: string;
    name: string;
    departmentId: string; // Gekoppeld aan Department.id
    startDate: string;
    status: EmployeeStatus;
    tasks: Task[];
    offboardingTasks: Task[];
}

export interface User {
    id: string;
    name: string;
    email: string;
    role: string;
    dienstId: string; // Gekoppeld aan Department.id
}

export interface AppState {
    user: User | null;
    departments: Department[];
    templateTasks: Task[];
    offboardingTemplateTasks: Task[];
    employees: Employee[];
    admins: User[];
    view: 'employees' | 'offboarding' | 'checklist' | 'template_onboarding' | 'template_offboarding' | 'admin_beheer' | 'dept_beheer';
    selectedEmployeeId: string | null;
    filterDienstId: string | 'All';
    filterCategory: Category | 'All';
    theme: Theme;
    // New fields
    employeeSearchQuery: string;
    showOnlyIncomplete: boolean;
}

export interface Artifact {
    id: string;
    status: 'streaming' | 'completed';
    html: string;
    styleName: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'SuperUser'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[] 
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <h3>{task.title}</h3>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v6_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    // Confirmation Modal States
    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v6_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienstId: 'All', employeeSearchQuery: '' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        // Apply search filter
        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;
        return currentTasks.filter(t => {
            const isDeptAllowed = state.user?.role === 'SuperUser' || t.dienst === state.user?.dienstId;
            if (!isDeptAllowed) return false;

            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;

            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    // Actions
    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            tasks: status === 'onboarding' ? state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : [],
            offboardingTasks: status === 'offboarding' ? state.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding', employeeSearchQuery: '' }));
        setIsEmpModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, departmentId: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, departmentId } : e)
        }));
        setEditingEmployee(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const startOffboarding = (id: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    return {
                        ...e,
                        status: 'offboarding',
                        offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                    };
                }
                return e;
            })
        }));
    };

    const addDepartment = (name: string) => {
        const newDept: Department = { id: generateId(), name };
        setState(prev => ({ ...prev, departments: [...prev.departments, newDept] }));
        setIsAddDeptModalOpen(false);
    };

    const deleteDepartment = (id: string) => {
        setState(prev => ({ ...prev, departments: prev.departments.filter(d => d.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId) return;
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(emp => {
                if (emp.id === prev.selectedEmployeeId) {
                    const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
                    return {
                        ...emp,
                        [taskType]: emp[taskType].map(t => {
                            if (t.id === taskId) {
                                const nextStatus = !t.isCompleted;
                                return {
                                    ...t,
                                    isCompleted: nextStatus,
                                    completedBy: nextStatus ? prev.user?.name : undefined,
                                    completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                };
                            }
                            return t;
                        })
                    };
                }
                return emp;
            })
        }));
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {/* Employee Lists */}
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Medewerker zoeken..." 
                                            className="search-input"
                                            value={state.employeeSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 16px',
                                                borderRadius: '4px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '240px'
                                            }}
                                        />
                                        {state.employeeSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, employeeSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Dienst</th><th>Datum</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.length > 0 ? accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const visibleTasks = currentTasks.filter(t => state.user!.role === 'SuperUser' || t.dienst === state.user!.dienstId);
                                        const completed = visibleTasks.filter(t => t.isCompleted).length;
                                        const total = visibleTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)}>✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)}>Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)}>🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    }) : (
                                        <tr><td colSpan={5} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen medewerkers gevonden.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Checklist View */}
                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Checklist: {selectedEmployee.name}</h1>
                                <div className="incomplete-toggle" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <input 
                                        type="checkbox" 
                                        id="incompleteOnly" 
                                        checked={state.showOnlyIncomplete} 
                                        onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} 
                                        style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                                    />
                                    <label htmlFor="incompleteOnly" style={{ cursor: 'pointer', fontSize: '14px', fontWeight: 500 }}>Alleen onvoltooid tonen</label>
                                </div>
                            </div>
                            <div className="filters">
                                <div className="filter-group">
                                    <label>Filter Dienst:</label>
                                    <select value={state.filterDienstId} onChange={(e) => setState(p => ({ ...p, filterDienstId: e.target.value }))}>
                                        <option value="All">Alle</option>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                </div>
                                <div className="filter-group">
                                    <label>Categorie:</label>
                                    <select value={state.filterCategory} onChange={(e) => setState(p => ({ ...p, filterCategory: e.target.value as any }))}>
                                        <option value="All">Alle</option>
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.length > 0 ? filteredTasks.map(task => (
                                <TaskCard key={task.id} task={task} onToggle={toggleEmployeeTask} departments={state.departments} />
                            )) : (
                                <div style={{textAlign: 'center', padding: '60px', background: 'var(--surface)', borderRadius: '8px', border: '1px dashed var(--border)', color: 'var(--text-muted)'}}>
                                    Geen taken gevonden voor de huidige filters.
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Template Managers */}
                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template' : 'Offboarding Template'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const isOff = state.view === 'template_offboarding';
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false
                                };
                                setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: [...prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId" required>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                    <select name="cat">
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                    <button type="submit" className="primary-action-btn">Toevoegen</button>
                                </div>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => (
                                <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                    const isOff = state.view === 'template_offboarding';
                                    setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'].filter(t => t.id !== id) }));
                                }} departments={state.departments} />
                            ))}
                        </div>
                    </div>
                )}

                {/* Beheer Views (SuperUser only) */}
                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Diensten</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.departments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setConfirmDeleteDept(d.id)}>🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Admins</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))}>🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            {/* Confirmation Dialogs */}
            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Medewerker verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen? Alle voortgang en data gaan onherroepelijk verloren."
                confirmText="Verwijderen"
            />

            <ConfirmationModal 
                isOpen={!!confirmDeleteDept}
                onClose={() => setConfirmDeleteDept(null)}
                onConfirm={() => confirmDeleteDept && deleteDepartment(confirmDeleteDept)}
                title="Dienst verwijderen"
                message="Weet u zeker dat u deze dienst wilt verwijderen? Dit kan invloed hebben op medewerkers en taken die aan deze dienst zijn gekoppeld."
                confirmText="Dienst verwijderen"
            />

            {/* Modals */}
            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker ${empModalStatus}`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.name.value, form.deptId.value, empModalStatus);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required autoFocus /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="deptId">
                            {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); addDepartment((e.target as any).name.value); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Admin">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rol</label>
                        <select name="role"><option value="Admin">Admin</option><option value="SuperUser">SuperUser (IT)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Medewerker Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.name.value, form.deptId.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="name" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="deptId" defaultValue={editingEmployee.departmentId}>{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                        </div>
                        <div className="modal-footer"><button type="submit" className="primary-action-btn">Opslaan</button></div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'Hoofdbeheer'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met laden...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[] 
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <h3>{task.title}</h3>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v7_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    // Confirmation Modal States
    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v7_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienstId: 'All', employeeSearchQuery: '' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        // Apply search filter
        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;
        return currentTasks.filter(t => {
            const isDeptAllowed = state.user?.role === 'SuperUser' || t.dienst === state.user?.dienstId;
            if (!isDeptAllowed) return false;

            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;

            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    // Actions
    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            tasks: status === 'onboarding' ? state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : [],
            offboardingTasks: status === 'offboarding' ? state.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding', employeeSearchQuery: '' }));
        setIsEmpModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, departmentId: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, departmentId } : e)
        }));
        setEditingEmployee(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const startOffboarding = (id: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    return {
                        ...e,
                        status: 'offboarding',
                        offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                    };
                }
                return e;
            })
        }));
    };

    const addDepartment = (name: string) => {
        const newDept: Department = { id: generateId(), name };
        setState(prev => ({ ...prev, departments: [...prev.departments, newDept] }));
        setIsAddDeptModalOpen(false);
    };

    const deleteDepartment = (id: string) => {
        setState(prev => ({ ...prev, departments: prev.departments.filter(d => d.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId) return;
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(emp => {
                if (emp.id === prev.selectedEmployeeId) {
                    const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
                    return {
                        ...emp,
                        [taskType]: emp[taskType].map(t => {
                            if (t.id === taskId) {
                                const nextStatus = !t.isCompleted;
                                return {
                                    ...t,
                                    isCompleted: nextStatus,
                                    completedBy: nextStatus ? prev.user?.name : undefined,
                                    completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                };
                            }
                            return t;
                        })
                    };
                }
                return emp;
            })
        }));
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {/* Employee Lists */}
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Zoek medewerker..." 
                                            className="search-input"
                                            value={state.employeeSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 32px 10px 12px',
                                                borderRadius: '6px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '240px',
                                                fontSize: '14px'
                                            }}
                                        />
                                        {state.employeeSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, employeeSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '18px' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Dienst</th><th>Startdatum</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.length > 0 ? accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const visibleTasks = currentTasks.filter(t => state.user!.role === 'SuperUser' || t.dienst === state.user!.dienstId);
                                        const completed = visibleTasks.filter(t => t.isCompleted).length;
                                        const total = visibleTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)} title="Bewerken">✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)} title="Verplaats naar Offboarding">Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)} title="Verwijderen">🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    }) : (
                                        <tr><td colSpan={5} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen resultaten gevonden voor "{state.employeeSearchQuery}".</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Checklist View */}
                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug naar overzicht</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Checklist: {selectedEmployee.name}</h1>
                                <div className="incomplete-toggle" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <input 
                                        type="checkbox" 
                                        id="incompleteOnly" 
                                        checked={state.showOnlyIncomplete} 
                                        onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} 
                                        style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                                    />
                                    <label htmlFor="incompleteOnly" style={{ cursor: 'pointer', fontSize: '14px', fontWeight: 500 }}>Toon alleen onvoltooid</label>
                                </div>
                            </div>
                            <div className="filters">
                                <div className="filter-group">
                                    <label>Filter Dienst:</label>
                                    <select value={state.filterDienstId} onChange={(e) => setState(p => ({ ...p, filterDienstId: e.target.value }))}>
                                        <option value="All">Alle diensten</option>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                </div>
                                <div className="filter-group">
                                    <label>Categorie:</label>
                                    <select value={state.filterCategory} onChange={(e) => setState(p => ({ ...p, filterCategory: e.target.value as any }))}>
                                        <option value="All">Alle categorieën</option>
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.length > 0 ? filteredTasks.map(task => (
                                <TaskCard key={task.id} task={task} onToggle={toggleEmployeeTask} departments={state.departments} />
                            )) : (
                                <div style={{textAlign: 'center', padding: '60px', background: 'var(--surface)', borderRadius: '8px', border: '1px dashed var(--border)', color: 'var(--text-muted)'}}>
                                    Er zijn geen taken die voldoen aan de geselecteerde filters.
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Template Managers */}
                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template Beheer' : 'Offboarding Template Beheer'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const isOff = state.view === 'template_offboarding';
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false
                                };
                                setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: [...prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving (optioneel)" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId" required>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                    <select name="cat">
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                    <button type="submit" className="primary-action-btn">Taak Toevoegen</button>
                                </div>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => (
                                <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                    const isOff = state.view === 'template_offboarding';
                                    setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'].filter(t => t.id !== id) }));
                                }} departments={state.departments} />
                            ))}
                        </div>
                    </div>
                )}

                {/* Beheer Views (SuperUser only) */}
                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Diensten</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Dienstnaam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.departments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setConfirmDeleteDept(d.id)} title="Dienst verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Admins</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Gekoppelde Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name || 'Geen'}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))} title="Admin verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            {/* Confirmation Dialogs */}
            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Medewerker verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen? Alle voortgang en taken voor deze persoon gaan onherroepelijk verloren."
                confirmText="Verwijderen"
            />

            <ConfirmationModal 
                isOpen={!!confirmDeleteDept}
                onClose={() => setConfirmDeleteDept(null)}
                onConfirm={() => confirmDeleteDept && deleteDepartment(confirmDeleteDept)}
                title="Dienst verwijderen"
                message="Weet u zeker dat u deze dienst wilt verwijderen? Dit kan gevolgen hebben voor admins en taken die aan deze dienst gekoppeld zijn."
                confirmText="Dienst verwijderen"
            />

            {/* Modals */}
            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker Toevoegen (${empModalStatus})`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.name.value, form.deptId.value, empModalStatus);
                }}>
                    <div className="form-group"><label>Volledige Naam</label><input name="name" required autoFocus /></div>
                    <div className="form-group">
                        <label>Afdeling / Dienst</label>
                        <select name="deptId">
                            {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Medewerker Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst Toevoegen">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); addDepartment((e.target as any).name.value); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" placeholder="Bijv. Marketing, HR, etc." required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Administrator">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Gekoppelde Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rechtenniveau</label>
                        <select name="role"><option value="Admin">Afdeling-Admin</option><option value="SuperUser">SuperUser (IT/Hoofdbeheer)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Admin Opslaan</button></div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Gegevens Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.name.value, form.deptId.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="name" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="deptId" defaultValue={editingEmployee.departmentId}>{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                        </div>
                        <div className="modal-footer"><button type="submit" className="primary-action-btn">Wijzigingen Opslaan</button></div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'Hoofdbeheer'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met laden...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[] 
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit && !isTemplate ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <h3>{task.title}</h3>
                            {!canEdit && !isTemplate && <span style={{ fontSize: '10px', background: 'var(--border)', padding: '2px 6px', borderRadius: '10px', color: 'var(--text-muted)' }}>Alleen lezen</span>}
                        </div>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v8_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    // Confirmation Modal States
    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v8_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienstId: 'All', employeeSearchQuery: '' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        // Apply search filter
        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;

        // BEWERKING: We filteren NIET meer op dienstId van de user.
        // Iedereen ziet alles, maar canEdit wordt straks bepaald bij het renderen.
        return currentTasks.filter(t => {
            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;

            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    // Actions
    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            tasks: status === 'onboarding' ? state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : [],
            offboardingTasks: status === 'offboarding' ? state.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding', employeeSearchQuery: '' }));
        setIsEmpModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, departmentId: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, departmentId } : e)
        }));
        setEditingEmployee(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const startOffboarding = (id: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    return {
                        ...e,
                        status: 'offboarding',
                        offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                    };
                }
                return e;
            })
        }));
    };

    const addDepartment = (name: string) => {
        const newDept: Department = { id: generateId(), name };
        setState(prev => ({ ...prev, departments: [...prev.departments, newDept] }));
        setIsAddDeptModalOpen(false);
    };

    const deleteDepartment = (id: string) => {
        setState(prev => ({ ...prev, departments: prev.departments.filter(d => d.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId || !state.user) return;

        setState(prev => {
            const empIndex = prev.employees.findIndex(e => e.id === prev.selectedEmployeeId);
            if (empIndex === -1) return prev;

            const emp = prev.employees[empIndex];
            const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
            const task = emp[taskType].find(t => t.id === taskId);

            // SECURITY CHECK: Alleen eigen dienst of SuperUser
            const isAuthorized = prev.user?.role === 'SuperUser' || task?.dienst === prev.user?.dienstId;
            if (!isAuthorized) return prev;

            return {
                ...prev,
                employees: prev.employees.map((e, idx) => {
                    if (idx === empIndex) {
                        return {
                            ...e,
                            [taskType]: e[taskType].map(t => {
                                if (t.id === taskId) {
                                    const nextStatus = !t.isCompleted;
                                    return {
                                        ...t,
                                        isCompleted: nextStatus,
                                        completedBy: nextStatus ? prev.user?.name : undefined,
                                        completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                    };
                                }
                                return t;
                            })
                        };
                    }
                    return e;
                })
            };
        });
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {/* Employee Lists */}
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Zoek medewerker..." 
                                            className="search-input"
                                            value={state.employeeSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 32px 10px 12px',
                                                borderRadius: '6px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '240px',
                                                fontSize: '14px'
                                            }}
                                        />
                                        {state.employeeSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, employeeSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '18px' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Dienst</th><th>Startdatum</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.length > 0 ? accessibleEmployees.map(emp => {
                                        // Voortgang berekenen over ALLE taken
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const completed = currentTasks.filter(t => t.isCompleted).length;
                                        const total = currentTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)} title="Bewerken">✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)} title="Verplaats naar Offboarding">Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)} title="Verwijderen">🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    }) : (
                                        <tr><td colSpan={5} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen resultaten gevonden voor "{state.employeeSearchQuery}".</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Checklist View */}
                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug naar overzicht</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Checklist: {selectedEmployee.name}</h1>
                                <div className="incomplete-toggle" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <input 
                                        type="checkbox" 
                                        id="incompleteOnly" 
                                        checked={state.showOnlyIncomplete} 
                                        onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} 
                                        style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                                    />
                                    <label htmlFor="incompleteOnly" style={{ cursor: 'pointer', fontSize: '14px', fontWeight: 500 }}>Toon alleen onvoltooid</label>
                                </div>
                            </div>
                            <div className="filters">
                                <div className="filter-group">
                                    <label>Filter Dienst:</label>
                                    <select value={state.filterDienstId} onChange={(e) => setState(p => ({ ...p, filterDienstId: e.target.value }))}>
                                        <option value="All">Alle diensten</option>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                </div>
                                <div className="filter-group">
                                    <label>Categorie:</label>
                                    <select value={state.filterCategory} onChange={(e) => setState(p => ({ ...p, filterCategory: e.target.value as any }))}>
                                        <option value="All">Alle categorieën</option>
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.length > 0 ? filteredTasks.map(task => {
                                // RECHTEN CHECK: Alleen bewerkbaar als eigen dienst OF superuser
                                const canEdit = state.user?.role === 'SuperUser' || task.dienst === state.user?.dienstId;
                                return (
                                    <TaskCard 
                                        key={task.id} 
                                        task={task} 
                                        onToggle={toggleEmployeeTask} 
                                        departments={state.departments} 
                                        canEdit={canEdit}
                                    />
                                );
                            }) : (
                                <div style={{textAlign: 'center', padding: '60px', background: 'var(--surface)', borderRadius: '8px', border: '1px dashed var(--border)', color: 'var(--text-muted)'}}>
                                    Er zijn geen taken die voldoen aan de geselecteerde filters.
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Template Managers */}
                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template Beheer' : 'Offboarding Template Beheer'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const isOff = state.view === 'template_offboarding';
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false
                                };
                                setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: [...prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving (optioneel)" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId" required>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                    <select name="cat">
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                    <button type="submit" className="primary-action-btn">Taak Toevoegen</button>
                                </div>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => {
                                // In template beheer mag je alles wijzigen als je er bent
                                return (
                                    <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                        const isOff = state.view === 'template_offboarding';
                                        setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'].filter(t => t.id !== id) }));
                                    }} departments={state.departments} />
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* Beheer Views (SuperUser only) */}
                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Diensten</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Dienstnaam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.departments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setConfirmDeleteDept(d.id)} title="Dienst verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Admins</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Gekoppelde Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name || 'Geen'}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))} title="Admin verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            {/* Confirmation Dialogs */}
            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Medewerker verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen? Alle voortgang en taken voor deze persoon gaan onherroepelijk verloren."
                confirmText="Verwijderen"
            />

            <ConfirmationModal 
                isOpen={!!confirmDeleteDept}
                onClose={() => setConfirmDeleteDept(null)}
                onConfirm={() => confirmDeleteDept && deleteDepartment(confirmDeleteDept)}
                title="Dienst verwijderen"
                message="Weet u zeker dat u deze dienst wilt verwijderen? Dit kan gevolgen hebben voor admins en taken die aan deze dienst gekoppeld zijn."
                confirmText="Dienst verwijderen"
            />

            {/* Modals */}
            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker Toevoegen (${empModalStatus})`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.name.value, form.deptId.value, empModalStatus);
                }}>
                    <div className="form-group"><label>Volledige Naam</label><input name="name" required autoFocus /></div>
                    <div className="form-group">
                        <label>Afdeling / Dienst</label>
                        <select name="deptId">
                            {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Medewerker Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst Toevoegen">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); addDepartment((e.target as any).name.value); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" placeholder="Bijv. Marketing, HR, etc." required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Administrator">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Gekoppelde Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rechtenniveau</label>
                        <select name="role"><option value="Admin">Afdeling-Admin</option><option value="SuperUser">SuperUser (IT/Hoofdbeheer)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Admin Opslaan</button></div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Gegevens Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.name.value, form.deptId.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="name" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="deptId" defaultValue={editingEmployee.departmentId}>{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                        </div>
                        <div className="modal-footer"><button type="submit" className="primary-action-btn">Wijzigingen Opslaan</button></div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

// Added optional children to Modal props to fix 'Property children is missing' errors
const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children?: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'Hoofdbeheer'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met laden...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

// Added key to TaskCard props to solve 'Property key does not exist' TS errors in JSX lists
const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[], key?: React.Key
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit && !isTemplate ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <h3>{task.title}</h3>
                            {!canEdit && !isTemplate && <span style={{ fontSize: '10px', background: 'var(--border)', padding: '2px 6px', borderRadius: '10px', color: 'var(--text-muted)' }}>Alleen lezen</span>}
                        </div>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v8_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    // Confirmation Modal States
    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v8_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienstId: 'All', employeeSearchQuery: '' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        // Apply search filter
        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;

        // BEWERKING: We filteren NIET meer op dienstId van de user.
        // Iedereen ziet alles, maar canEdit wordt straks bepaald bij het renderen.
        return currentTasks.filter(t => {
            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;

            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    // Actions
    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            tasks: status === 'onboarding' ? state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : [],
            offboardingTasks: status === 'offboarding' ? state.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding', employeeSearchQuery: '' }));
        setIsEmpModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, departmentId: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, departmentId } : e)
        }));
        setEditingEmployee(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const startOffboarding = (id: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    return {
                        ...e,
                        status: 'offboarding',
                        offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                    };
                }
                return e;
            })
        }));
    };

    const addDepartment = (name: string) => {
        const newDept: Department = { id: generateId(), name };
        setState(prev => ({ ...prev, departments: [...prev.departments, newDept] }));
        setIsAddDeptModalOpen(false);
    };

    const deleteDepartment = (id: string) => {
        setState(prev => ({ ...prev, departments: prev.departments.filter(d => d.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId || !state.user) return;

        setState(prev => {
            const empIndex = prev.employees.findIndex(e => e.id === prev.selectedEmployeeId);
            if (empIndex === -1) return prev;

            const emp = prev.employees[empIndex];
            const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
            const task = emp[taskType].find(t => t.id === taskId);

            // SECURITY CHECK: Alleen eigen dienst of SuperUser
            const isAuthorized = prev.user?.role === 'SuperUser' || task?.dienst === prev.user?.dienstId;
            if (!isAuthorized) return prev;

            return {
                ...prev,
                employees: prev.employees.map((e, idx) => {
                    if (idx === empIndex) {
                        return {
                            ...e,
                            [taskType]: e[taskType].map(t => {
                                if (t.id === taskId) {
                                    const nextStatus = !t.isCompleted;
                                    return {
                                        ...t,
                                        isCompleted: nextStatus,
                                        completedBy: nextStatus ? prev.user?.name : undefined,
                                        completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                    };
                                }
                                return t;
                            })
                        };
                    }
                    return e;
                })
            };
        });
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {/* Employee Lists */}
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Zoek medewerker..." 
                                            className="search-input"
                                            value={state.employeeSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 32px 10px 12px',
                                                borderRadius: '6px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '240px',
                                                fontSize: '14px'
                                            }}
                                        />
                                        {state.employeeSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, employeeSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '18px' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Dienst</th><th>Startdatum</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.length > 0 ? accessibleEmployees.map(emp => {
                                        // Voortgang berekenen over ALLE taken
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const completed = currentTasks.filter(t => t.isCompleted).length;
                                        const total = currentTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)} title="Bewerken">✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)} title="Verplaats naar Offboarding">Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)} title="Verwijderen">🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    }) : (
                                        <tr><td colSpan={5} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen resultaten gevonden voor "{state.employeeSearchQuery}".</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Checklist View */}
                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug naar overzicht</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Checklist: {selectedEmployee.name}</h1>
                                <div className="incomplete-toggle" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <input 
                                        type="checkbox" 
                                        id="incompleteOnly" 
                                        checked={state.showOnlyIncomplete} 
                                        onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} 
                                        style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                                    />
                                    <label htmlFor="incompleteOnly" style={{ cursor: 'pointer', fontSize: '14px', fontWeight: 500 }}>Toon alleen onvoltooid</label>
                                </div>
                            </div>
                            <div className="filters">
                                <div className="filter-group">
                                    <label>Filter Dienst:</label>
                                    <select value={state.filterDienstId} onChange={(e) => setState(p => ({ ...p, filterDienstId: e.target.value }))}>
                                        <option value="All">Alle diensten</option>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                </div>
                                <div className="filter-group">
                                    <label>Categorie:</label>
                                    <select value={state.filterCategory} onChange={(e) => setState(p => ({ ...p, filterCategory: e.target.value as any }))}>
                                        <option value="All">Alle categorieën</option>
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.length > 0 ? filteredTasks.map(task => {
                                // RECHTEN CHECK: Alleen bewerkbaar als eigen dienst OF superuser
                                const canEdit = state.user?.role === 'SuperUser' || task.dienst === state.user?.dienstId;
                                return (
                                    <TaskCard 
                                        key={task.id} 
                                        task={task} 
                                        onToggle={toggleEmployeeTask} 
                                        departments={state.departments} 
                                        canEdit={canEdit}
                                    />
                                );
                            }) : (
                                <div style={{textAlign: 'center', padding: '60px', background: 'var(--surface)', borderRadius: '8px', border: '1px dashed var(--border)', color: 'var(--text-muted)'}}>
                                    Er zijn geen taken die voldoen aan de geselecteerde filters.
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Template Managers */}
                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template Beheer' : 'Offboarding Template Beheer'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const isOff = state.view === 'template_offboarding';
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false
                                };
                                setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: [...prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving (optioneel)" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId" required>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                    <select name="cat">
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                    <button type="submit" className="primary-action-btn">Taak Toevoegen</button>
                                </div>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => {
                                // In template beheer mag je alles wijzigen als je er bent
                                return (
                                    <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                        const isOff = state.view === 'template_offboarding';
                                        setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'].filter(t => t.id !== id) }));
                                    }} departments={state.departments} />
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* Beheer Views (SuperUser only) */}
                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Diensten</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Dienstnaam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.departments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setConfirmDeleteDept(d.id)} title="Dienst verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Admins</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Gekoppelde Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name || 'Geen'}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))} title="Admin verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            {/* Confirmation Dialogs */}
            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Medewerker verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen? Alle voortgang en taken voor deze persoon gaan onherroepelijk verloren."
                confirmText="Verwijderen"
            />

            <ConfirmationModal 
                isOpen={!!confirmDeleteDept}
                onClose={() => setConfirmDeleteDept(null)}
                onConfirm={() => confirmDeleteDept && deleteDepartment(confirmDeleteDept)}
                title="Dienst verwijderen"
                message="Weet u zeker dat u deze dienst wilt verwijderen? Dit kan gevolgen hebben voor admins en taken die aan deze dienst gekoppeld zijn."
                confirmText="Dienst verwijderen"
            />

            {/* Modals */}
            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker Toevoegen (${empModalStatus})`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.name.value, form.deptId.value, empModalStatus);
                }}>
                    <div className="form-group"><label>Volledige Naam</label><input name="name" required autoFocus /></div>
                    <div className="form-group">
                        <label>Afdeling / Dienst</label>
                        <select name="deptId">
                            {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Medewerker Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst Toevoegen">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); addDepartment((e.target as any).name.value); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" placeholder="Bijv. Marketing, HR, etc." required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Administrator">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Gekoppelde Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rechtenniveau</label>
                        <select name="role"><option value="Admin">Afdeling-Admin</option><option value="SuperUser">SuperUser (IT/Hoofdbeheer)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Admin Opslaan</button></div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Gegevens Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.name.value, form.deptId.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="name" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="deptId" defaultValue={editingEmployee.departmentId}>{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                        </div>
                        <div className="modal-footer"><button type="submit" className="primary-action-btn">Wijzigingen Opslaan</button></div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

export type Category = 'Account' | 'Software' | 'Hardware' | 'Toegang';
export type EmployeeStatus = 'onboarding' | 'offboarding';
export type Theme = 'light' | 'dark';

export interface Department {
    id: string;
    name: string;
}

export interface Task {
    id: string;
    title: string;
    description?: string;
    dienst: string; // Veranderd naar string voor dynamische koppeling
    category: Category;
    isCompleted: boolean;
    completedBy?: string;
    completedAt?: string;
}

export interface Employee {
    id: string;
    name: string;
    departmentId: string; // Gekoppeld aan Department.id
    startDate: string;
    status: EmployeeStatus;
    tasks: Task[];
    offboardingTasks: Task[];
}

export interface User {
    id: string;
    name: string;
    email: string;
    role: string;
    dienstId: string; // Gekoppeld aan Department.id
}

export interface AppState {
    user: User | null;
    departments: Department[];
    templateTasks: Task[];
    offboardingTemplateTasks: Task[];
    employees: Employee[];
    admins: User[];
    view: 'employees' | 'offboarding' | 'checklist' | 'template_onboarding' | 'template_offboarding' | 'admin_beheer' | 'dept_beheer';
    selectedEmployeeId: string | null;
    filterDienstId: string | 'All';
    filterCategory: Category | 'All';
    theme: Theme;
    employeeSearchQuery: string;
    showOnlyIncomplete: boolean;
    // New fields for Beheer views
    deptSearchQuery: string;
    adminSearchQuery: string;
}

export interface Artifact {
    id: string;
    status: 'streaming' | 'completed';
    html: string;
    styleName: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children?: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'Hoofdbeheer'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met laden...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[], key?: React.Key
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit && !isTemplate ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <h3>{task.title}</h3>
                            {!canEdit && !isTemplate && <span style={{ fontSize: '10px', background: 'var(--border)', padding: '2px 6px', borderRadius: '10px', color: 'var(--text-muted)' }}>Alleen lezen</span>}
                        </div>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v9_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false,
            deptSearchQuery: '',
            adminSearchQuery: ''
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v9_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user, filterDienstId: 'All', employeeSearchQuery: '', deptSearchQuery: '', adminSearchQuery: '' }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const filteredDepartments = useMemo(() => {
        if (!state.deptSearchQuery) return state.departments;
        const query = state.deptSearchQuery.toLowerCase();
        return state.departments.filter(d => d.name.toLowerCase().includes(query));
    }, [state.departments, state.deptSearchQuery]);

    const filteredAdmins = useMemo(() => {
        if (!state.adminSearchQuery) return state.admins;
        const query = state.adminSearchQuery.toLowerCase();
        return state.admins.filter(a => 
            a.name.toLowerCase().includes(query) || 
            a.email.toLowerCase().includes(query)
        );
    }, [state.admins, state.adminSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;

        return currentTasks.filter(t => {
            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;

            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus) => {
        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            tasks: status === 'onboarding' ? state.templateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : [],
            offboardingTasks: status === 'offboarding' ? state.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false })) : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding', employeeSearchQuery: '' }));
        setIsEmpModalOpen(false);
    };

    const updateEmployee = (id: string, name: string, departmentId: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => e.id === id ? { ...e, name, departmentId } : e)
        }));
        setEditingEmployee(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const startOffboarding = (id: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    return {
                        ...e,
                        status: 'offboarding',
                        offboardingTasks: prev.offboardingTemplateTasks.map(t => ({ ...t, id: generateId(), isCompleted: false }))
                    };
                }
                return e;
            })
        }));
    };

    const addDepartment = (name: string) => {
        const newDept: Department = { id: generateId(), name };
        setState(prev => ({ ...prev, departments: [...prev.departments, newDept] }));
        setIsAddDeptModalOpen(false);
    };

    const deleteDepartment = (id: string) => {
        setState(prev => ({ ...prev, departments: prev.departments.filter(d => d.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId || !state.user) return;

        setState(prev => {
            const empIndex = prev.employees.findIndex(e => e.id === prev.selectedEmployeeId);
            if (empIndex === -1) return prev;

            const emp = prev.employees[empIndex];
            const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
            const task = emp[taskType].find(t => t.id === taskId);

            const isAuthorized = prev.user?.role === 'SuperUser' || task?.dienst === prev.user?.dienstId;
            if (!isAuthorized) return prev;

            return {
                ...prev,
                employees: prev.employees.map((e, idx) => {
                    if (idx === empIndex) {
                        return {
                            ...e,
                            [taskType]: e[taskType].map(t => {
                                if (t.id === taskId) {
                                    const nextStatus = !t.isCompleted;
                                    return {
                                        ...t,
                                        isCompleted: nextStatus,
                                        completedBy: nextStatus ? prev.user?.name : undefined,
                                        completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                    };
                                }
                                return t;
                            })
                        };
                    }
                    return e;
                })
            };
        });
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '', deptSearchQuery: '', adminSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Zoek medewerker..." 
                                            className="search-input"
                                            value={state.employeeSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 32px 10px 12px',
                                                borderRadius: '6px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '240px',
                                                fontSize: '14px'
                                            }}
                                        />
                                        {state.employeeSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, employeeSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '18px' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Dienst</th><th>Startdatum</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.length > 0 ? accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const completed = currentTasks.filter(t => t.isCompleted).length;
                                        const total = currentTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td>{emp.startDate}</td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)} title="Bewerken">✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => startOffboarding(emp.id)} title="Verplaats naar Offboarding">Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)} title="Verwijderen">🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    }) : (
                                        <tr><td colSpan={5} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen resultaten gevonden voor "{state.employeeSearchQuery}".</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug naar overzicht</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Checklist: {selectedEmployee.name}</h1>
                                <div className="incomplete-toggle" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                    <input 
                                        type="checkbox" 
                                        id="incompleteOnly" 
                                        checked={state.showOnlyIncomplete} 
                                        onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} 
                                        style={{ width: '18px', height: '18px', cursor: 'pointer' }}
                                    />
                                    <label htmlFor="incompleteOnly" style={{ cursor: 'pointer', fontSize: '14px', fontWeight: 500 }}>Toon alleen onvoltooid</label>
                                </div>
                            </div>
                            <div className="filters">
                                <div className="filter-group">
                                    <label>Filter Dienst:</label>
                                    <select value={state.filterDienstId} onChange={(e) => setState(p => ({ ...p, filterDienstId: e.target.value }))}>
                                        <option value="All">Alle diensten</option>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                </div>
                                <div className="filter-group">
                                    <label>Categorie:</label>
                                    <select value={state.filterCategory} onChange={(e) => setState(p => ({ ...p, filterCategory: e.target.value as any }))}>
                                        <option value="All">Alle categorieën</option>
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.length > 0 ? filteredTasks.map(task => {
                                const canEdit = state.user?.role === 'SuperUser' || task.dienst === state.user?.dienstId;
                                return (
                                    <TaskCard 
                                        key={task.id} 
                                        task={task} 
                                        onToggle={toggleEmployeeTask} 
                                        departments={state.departments} 
                                        canEdit={canEdit}
                                    />
                                );
                            }) : (
                                <div style={{textAlign: 'center', padding: '60px', background: 'var(--surface)', borderRadius: '8px', border: '1px dashed var(--border)', color: 'var(--text-muted)'}}>
                                    Er zijn geen taken die voldoen aan de geselecteerde filters.
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template Beheer' : 'Offboarding Template Beheer'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const isOff = state.view === 'template_offboarding';
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false
                                };
                                setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: [...prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving (optioneel)" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId" required>
                                        {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                                    </select>
                                    <select name="cat">
                                        <option value="Account">Account</option><option value="Hardware">Hardware</option>
                                        <option value="Software">Software</option><option value="Toegang">Toegang</option>
                                    </select>
                                    <button type="submit" className="primary-action-btn">Taak Toevoegen</button>
                                </div>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => {
                                return (
                                    <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                        const isOff = state.view === 'template_offboarding';
                                        setState(prev => ({ ...prev, [isOff ? 'offboardingTemplateTasks' : 'templateTasks']: prev[isOff ? 'offboardingTemplateTasks' : 'templateTasks'].filter(t => t.id !== id) }));
                                    }} departments={state.departments} />
                                );
                            })}
                        </div>
                    </div>
                )}

                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Beheer Diensten</h1>
                                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Zoek dienst..." 
                                            className="search-input"
                                            value={state.deptSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, deptSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 32px 10px 12px',
                                                borderRadius: '6px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '240px',
                                                fontSize: '14px'
                                            }}
                                        />
                                        {state.deptSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, deptSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '18px' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead><tr><th>Dienstnaam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {filteredDepartments.length > 0 ? filteredDepartments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setConfirmDeleteDept(d.id)} title="Dienst verwijderen">🗑</button></td></tr>
                                    )) : (
                                        <tr><td colSpan={2} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen diensten gevonden.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>Beheer Admins</h1>
                                <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                                    <div className="search-container" style={{ position: 'relative' }}>
                                        <input 
                                            type="text" 
                                            placeholder="Zoek admin (naam/email)..." 
                                            className="search-input"
                                            value={state.adminSearchQuery}
                                            onChange={(e) => setState(p => ({ ...p, adminSearchQuery: e.target.value }))}
                                            style={{
                                                padding: '10px 32px 10px 12px',
                                                borderRadius: '6px',
                                                border: '1px solid var(--border)',
                                                background: 'var(--input-bg)',
                                                color: 'var(--text)',
                                                width: '260px',
                                                fontSize: '14px'
                                            }}
                                        />
                                        {state.adminSearchQuery && (
                                            <button 
                                                onClick={() => setState(p => ({ ...p, adminSearchQuery: '' }))}
                                                style={{ position: 'absolute', right: '10px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '18px' }}
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                    <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Gekoppelde Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {filteredAdmins.length > 0 ? filteredAdmins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name || 'Geen'}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))} title="Admin verwijderen">🗑</button></td></tr>
                                    )) : (
                                        <tr><td colSpan={4} style={{textAlign: 'center', padding: '40px', color: 'var(--text-muted)'}}>Geen beheerders gevonden.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Medewerker verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen? Alle voortgang en taken voor deze persoon gaan onherroepelijk verloren."
                confirmText="Verwijderen"
            />

            <ConfirmationModal 
                isOpen={!!confirmDeleteDept}
                onClose={() => setConfirmDeleteDept(null)}
                onConfirm={() => confirmDeleteDept && deleteDepartment(confirmDeleteDept)}
                title="Dienst verwijderen"
                message="Weet u zeker dat u deze dienst wilt verwijderen? Dit kan gevolgen hebben voor admins en taken die aan deze dienst gekoppeld zijn."
                confirmText="Dienst verwijderen"
            />

            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker Toevoegen (${empModalStatus})`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    createEmployee(form.name.value, form.deptId.value, empModalStatus);
                }}>
                    <div className="form-group"><label>Volledige Naam</label><input name="name" required autoFocus /></div>
                    <div className="form-group">
                        <label>Afdeling / Dienst</label>
                        <select name="deptId">
                            {state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Medewerker Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst Toevoegen">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); addDepartment((e.target as any).name.value); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" placeholder="Bijv. Marketing, HR, etc." required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Administrator">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Gekoppelde Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rechtenniveau</label>
                        <select name="role"><option value="Admin">Afdeling-Admin</option><option value="SuperUser">SuperUser (IT/Hoofdbeheer)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Admin Opslaan</button></div>
                </form>
            </Modal>

            <Modal isOpen={!!editingEmployee} onClose={() => setEditingEmployee(null)} title="Gegevens Bewerken">
                {editingEmployee && (
                    <form className="add-emp-form" onSubmit={(e) => {
                        e.preventDefault();
                        const form = e.target as any;
                        updateEmployee(editingEmployee.id, form.name.value, form.deptId.value);
                    }}>
                        <div className="form-group"><label>Naam</label><input name="name" defaultValue={editingEmployee.name} required /></div>
                        <div className="form-group">
                            <label>Dienst</label>
                            <select name="deptId" defaultValue={editingEmployee.departmentId}>{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                        </div>
                        <div className="modal-footer"><button type="submit" className="primary-action-btn">Wijzigingen Opslaan</button></div>
                    </form>
                )}
            </Modal>
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

export type Category = 'Account' | 'Software' | 'Hardware' | 'Toegang';
export type EmployeeStatus = 'onboarding' | 'offboarding';
export type Theme = 'light' | 'dark';

export interface Department {
    id: string;
    name: string;
}

export interface Task {
    id: string;
    title: string;
    description?: string;
    dienst: string;
    category: Category;
    isCompleted: boolean;
    completedBy?: string;
    completedAt?: string;
    // Nieuw: Voor welke scenario's is deze taak bedoeld? (Leeg = Altijd)
    applicableReasons?: string[]; 
}

export interface Employee {
    id: string;
    name: string;
    departmentId: string;
    startDate: string;
    status: EmployeeStatus;
    reason: string; // Bijv: 'Standaard', 'Overlijden', 'Verlof', etc.
    tasks: Task[];
    offboardingTasks: Task[];
}

export interface User {
    id: string;
    name: string;
    email: string;
    role: string;
    dienstId: string;
}

export interface AppState {
    user: User | null;
    departments: Department[];
    templateTasks: Task[];
    offboardingTemplateTasks: Task[];
    employees: Employee[];
    admins: User[];
    view: 'employees' | 'offboarding' | 'checklist' | 'template_onboarding' | 'template_offboarding' | 'admin_beheer' | 'dept_beheer';
    selectedEmployeeId: string | null;
    filterDienstId: string | 'All';
    filterCategory: Category | 'All';
    theme: Theme;
    employeeSearchQuery: string;
    showOnlyIncomplete: boolean;
    deptSearchQuery: string;
    adminSearchQuery: string;
}

export interface Artifact {
    id: string;
    status: 'streaming' | 'completed';
    html: string;
    styleName: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Constants voor Redenen ---
const ONBOARDING_REASONS = ['Nieuwe Medewerker', 'Terugkeer uit Verlof', 'Interne Transfer'];
const OFFBOARDING_REASONS = ['Ontslag', 'Langdurig Verlof', 'Pensionering', 'Overlijden'];

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView === 'admin_beheer' || currentView === 'dept_beheer' ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children?: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'Hoofdbeheer'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met laden...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[], key?: React.Key
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit && !isTemplate ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <h3>{task.title}</h3>
                            {!canEdit && !isTemplate && <span style={{ fontSize: '10px', background: 'var(--border)', padding: '2px 6px', borderRadius: '10px', color: 'var(--text-muted)' }}>Alleen lezen</span>}
                        </div>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                    {task.applicableReasons && task.applicableReasons.length > 0 && (
                        <span className="tag scenario" style={{ background: 'var(--warning)', color: '#000' }}>
                            {task.applicableReasons.join(', ')}
                        </span>
                    )}
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v10_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false,
            deptSearchQuery: '',
            adminSearchQuery: ''
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isOffboardTriggerModalOpen, setIsOffboardTriggerModalOpen] = useState<string | null>(null);
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v10_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;

        return currentTasks.filter(t => {
            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;
            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus, reason: string) => {
        // Filter taken op basis van reden
        const baseTasks = status === 'onboarding' ? state.templateTasks : state.offboardingTemplateTasks;
        const filteredInitialTasks = baseTasks.filter(t => 
            !t.applicableReasons || t.applicableReasons.length === 0 || t.applicableReasons.includes(reason)
        ).map(t => ({ ...t, id: generateId(), isCompleted: false }));

        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            reason,
            tasks: status === 'onboarding' ? filteredInitialTasks : [],
            offboardingTasks: status === 'offboarding' ? filteredInitialTasks : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding' }));
        setIsEmpModalOpen(false);
    };

    const startOffboarding = (id: string, reason: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    const filteredTasks = prev.offboardingTemplateTasks.filter(t => 
                        !t.applicableReasons || t.applicableReasons.length === 0 || t.applicableReasons.includes(reason)
                    ).map(t => ({ ...t, id: generateId(), isCompleted: false }));

                    return {
                        ...e,
                        status: 'offboarding',
                        reason,
                        offboardingTasks: filteredTasks
                    };
                }
                return e;
            }),
            view: 'offboarding'
        }));
        setIsOffboardTriggerModalOpen(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId || !state.user) return;

        setState(prev => {
            const empIndex = prev.employees.findIndex(e => e.id === prev.selectedEmployeeId);
            if (empIndex === -1) return prev;

            const emp = prev.employees[empIndex];
            const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
            const task = emp[taskType].find(t => t.id === taskId);

            const isAuthorized = prev.user?.role === 'SuperUser' || task?.dienst === prev.user?.dienstId;
            if (!isAuthorized) return prev;

            return {
                ...prev,
                employees: prev.employees.map((e, idx) => {
                    if (idx === empIndex) {
                        return {
                            ...e,
                            [taskType]: e[taskType].map(t => {
                                if (t.id === taskId) {
                                    const nextStatus = !t.isCompleted;
                                    return {
                                        ...t,
                                        isCompleted: nextStatus,
                                        completedBy: nextStatus ? prev.user?.name : undefined,
                                        completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                    };
                                }
                                return t;
                            })
                        };
                    }
                    return e;
                })
            };
        });
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px' }}>
                                    <input 
                                        type="text" 
                                        placeholder="Zoek medewerker..." 
                                        className="search-input"
                                        value={state.employeeSearchQuery}
                                        onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                        style={{ padding: '8px 12px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                                    />
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Scenario</th><th>Dienst</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const completed = currentTasks.filter(t => t.isCompleted).length;
                                        const total = currentTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="tag scenario" style={{ opacity: 0.8, fontSize: '10px' }}>{emp.reason}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)}>✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => setIsOffboardTriggerModalOpen(emp.id)}>Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)}>🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug naar overzicht</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <div>
                                    <h1>Checklist: {selectedEmployee.name}</h1>
                                    <p style={{ margin: '4px 0 0', color: 'var(--text-muted)', fontSize: '14px' }}>Scenario: <strong>{selectedEmployee.reason}</strong></p>
                                </div>
                                <div className="incomplete-toggle">
                                    <input type="checkbox" id="incompleteOnly" checked={state.showOnlyIncomplete} onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} />
                                    <label htmlFor="incompleteOnly">Toon alleen onvoltooid</label>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.map(task => {
                                const canEdit = state.user?.role === 'SuperUser' || task.dienst === state.user?.dienstId;
                                return <TaskCard key={task.id} task={task} onToggle={toggleEmployeeTask} departments={state.departments} canEdit={canEdit} />;
                            })}
                        </div>
                    </div>
                )}

                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template' : 'Offboarding Template'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const reasons = Array.from(form.applicableReasons.selectedOptions).map((o: any) => o.value).filter(v => v !== 'Alle');
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false,
                                    applicableReasons: reasons
                                };
                                const listKey = state.view === 'template_onboarding' ? 'templateTasks' : 'offboardingTemplateTasks';
                                setState(prev => ({ ...prev, [listKey]: [...prev[listKey], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                                    <select name="cat"><option value="Account">Account</option><option value="Hardware">Hardware</option><option value="Software">Software</option><option value="Toegang">Toegang</option></select>
                                    <select name="applicableReasons" multiple style={{ height: '60px' }}>
                                        <option value="Alle">Geldt voor iedereen</option>
                                        {(state.view === 'template_onboarding' ? ONBOARDING_REASONS : OFFBOARDING_REASONS).map(r => <option key={r} value={r}>{r}</option>)}
                                    </select>
                                    <button type="submit" className="primary-action-btn">Voeg toe aan template</button>
                                </div>
                                <small style={{ color: 'var(--text-muted)' }}>Houd Ctrl (of Cmd) ingedrukt om meerdere scenario's te selecteren.</small>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => (
                                <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                    const key = state.view === 'template_onboarding' ? 'templateTasks' : 'offboardingTemplateTasks';
                                    setState(p => ({ ...p, [key]: p[key].filter(t => t.id !== id) }));
                                }} departments={state.departments} />
                            ))}
                        </div>
                    </div>
                )}

                {/* ... Andere beheer-views (Diensten, Admins) blijven functioneel hetzelfde ... */}
            </main>

            {/* Reden-selectie voor Offboarding */}
            <Modal isOpen={!!isOffboardTriggerModalOpen} onClose={() => setIsOffboardTriggerModalOpen(null)} title="Offboarding Starten">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    startOffboarding(isOffboardTriggerModalOpen!, (e.target as any).reason.value);
                }}>
                    <p>Waarom verlaat deze medewerker de organisatie?</p>
                    <div className="form-group">
                        <label>Reden van vertrek</label>
                        <select name="reason">
                            {OFFBOARDING_REASONS.map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Start Offboarding Checklist</button></div>
                </form>
            </Modal>

            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker Toevoegen (${empModalStatus})`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const f = e.target as any;
                    createEmployee(f.name.value, f.deptId.value, empModalStatus, f.reason.value);
                }}>
                    <div className="form-group"><label>Volledige Naam</label><input name="name" required /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="deptId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Reden / Scenario</label>
                        <select name="reason">
                            {(empModalStatus === 'onboarding' ? ONBOARDING_REASONS : OFFBOARDING_REASONS).map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Aanmaken</button></div>
                </form>
            </Modal>

            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen?"
            />
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

export type Category = 'Account' | 'Software' | 'Hardware' | 'Toegang';
export type EmployeeStatus = 'onboarding' | 'offboarding';
export type Theme = 'light' | 'dark';

export interface Department {
    id: string;
    name: string;
}

export interface Task {
    id: string;
    title: string;
    description?: string;
    dienst: string;
    category: Category;
    isCompleted: boolean;
    completedBy?: string;
    completedAt?: string;
    applicableReasons?: string[]; 
}

export interface Employee {
    id: string;
    name: string;
    departmentId: string;
    startDate: string;
    status: EmployeeStatus;
    reason: string; 
    tasks: Task[];
    offboardingTasks: Task[];
}

export interface User {
    id: string;
    name: string;
    email: string;
    role: string;
    dienstId: string;
}

export interface AppState {
    user: User | null;
    departments: Department[];
    templateTasks: Task[];
    offboardingTemplateTasks: Task[];
    employees: Employee[];
    admins: User[];
    onboardingReasons: string[];
    offboardingReasons: string[];
    view: 'employees' | 'offboarding' | 'checklist' | 'template_onboarding' | 'template_offboarding' | 'admin_beheer' | 'dept_beheer' | 'reason_beheer';
    selectedEmployeeId: string | null;
    filterDienstId: string | 'All';
    filterCategory: Category | 'All';
    theme: Theme;
    employeeSearchQuery: string;
    showOnlyIncomplete: boolean;
    deptSearchQuery: string;
    adminSearchQuery: string;
}

export interface Artifact {
    id: string;
    status: 'streaming' | 'completed';
    html: string;
    styleName: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom/client';
import { Task, User, Category, AppState, Employee, EmployeeStatus, Theme, Department } from './types';
import { INITIAL_TASKS, INITIAL_OFFBOARDING_TASKS } from './constants';
import { generateId } from './utils';

// --- Components ---

const Navbar = ({ user, onLogout, setView, currentView, theme, onToggleTheme }: { 
    user: User, 
    onLogout: () => void, 
    setView: (v: any) => void, 
    currentView: string,
    theme: Theme,
    onToggleTheme: () => void
}) => (
    <nav className="nav-container">
        <div className="nav-logo">
            <span className="logo-icon">✓</span>
            <span className="logo-text">Portal</span>
        </div>
        <div className="nav-links">
            <button className={currentView === 'employees' || (currentView === 'checklist' && !currentView.includes('offboarding')) ? 'active' : ''} onClick={() => setView('employees')}>Onboarding</button>
            <button className={currentView === 'offboarding' ? 'active' : ''} onClick={() => setView('offboarding')}>Offboarding</button>
            <div className="nav-dropdown">
                <button className={currentView.includes('template') ? 'active' : ''}>Templates ▾</button>
                <div className="dropdown-content">
                    <button onClick={() => setView('template_onboarding')}>Onboarding Template</button>
                    <button onClick={() => setView('template_offboarding')}>Offboarding Template</button>
                </div>
            </div>
            {user.role === 'SuperUser' && (
                <div className="nav-dropdown">
                    <button className={currentView.includes('beheer') && !currentView.includes('template') ? 'active' : ''}>Beheer ▾</button>
                    <div className="dropdown-content">
                        <button onClick={() => setView('admin_beheer')}>Beheer Admins</button>
                        <button onClick={() => setView('dept_beheer')}>Beheer Diensten</button>
                        <button onClick={() => setView('reason_beheer')}>Beheer Scenario's</button>
                    </div>
                </div>
            )}
        </div>
        <div className="nav-user">
            <button onClick={onToggleTheme} className="theme-toggle" title="Wissel thema">
                {theme === 'light' ? '🌙' : '☀️'}
            </button>
            <div className="user-info">
                <span className="user-name">{user.name}</span>
                <span className="user-dept">{user.role}</span>
            </div>
            <button onClick={onLogout} className="logout-btn">Uitloggen</button>
        </div>
    </nav>
);

const Modal = ({ isOpen, onClose, title, children }: { isOpen: boolean, onClose: () => void, title: string, children?: React.ReactNode }) => {
    if (!isOpen) return null;
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <div className="modal-header">
                    <h2>{title}</h2>
                    <button className="close-x" onClick={onClose}>&times;</button>
                </div>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>
    );
};

const ConfirmationModal = ({ isOpen, onClose, onConfirm, title, message, confirmText = "Bevestigen", type = "danger" }: { 
    isOpen: boolean, onClose: () => void, onConfirm: () => void, title: string, message: string, confirmText?: string, type?: "danger" | "primary" 
}) => (
    <Modal isOpen={isOpen} onClose={onClose} title={title}>
        <p style={{ margin: '0 0 24px 0', fontSize: '14px', lineHeight: '1.5', color: 'var(--text)' }}>{message}</p>
        <div className="modal-footer" style={{ marginTop: 0 }}>
            <button className="secondary-btn" onClick={onClose}>Annuleren</button>
            <button 
                className="primary-action-btn" 
                style={type === 'danger' ? { backgroundColor: 'var(--danger)' } : {}} 
                onClick={() => { onConfirm(); onClose(); }}
            >
                {confirmText}
            </button>
        </div>
    </Modal>
);

const LoginScreen = ({ onLogin, admins, departments }: { onLogin: (u: User) => void, admins: User[], departments: Department[] }) => {
    const [isLoading, setIsLoading] = useState(false);
    const [selectedAdminId, setSelectedAdminId] = useState<string>(admins[0]?.id || '');

    const handleLogin = () => {
        const admin = admins.find(a => a.id === selectedAdminId);
        if (!admin) return;
        setIsLoading(true);
        setTimeout(() => {
            onLogin(admin);
        }, 800);
    };

    return (
        <div className="login-page">
            <div className="login-card">
                <div className="microsoft-logo">
                    <div className="square red"></div><div className="square green"></div>
                    <div className="square blue"></div><div className="square yellow"></div>
                </div>
                <h1>Aanmelden</h1>
                <p>Selecteer uw organisatie-account.</p>
                <div className="dept-selector" style={{ marginBottom: '20px', textAlign: 'left' }}>
                    <label style={{ fontSize: '12px', fontWeight: 600, display: 'block', marginBottom: '5px', color: 'var(--text)' }}>Account:</label>
                    <select 
                        value={selectedAdminId} 
                        onChange={(e) => setSelectedAdminId(e.target.value)}
                        style={{ width: '100%', padding: '10px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                    >
                        {admins.map(a => {
                            const dept = departments.find(d => d.id === a.dienstId);
                            return <option key={a.id} value={a.id}>{a.name} ({dept?.name || 'Hoofdbeheer'})</option>;
                        })}
                    </select>
                </div>
                <button className="sso-button" onClick={handleLogin} disabled={isLoading || !selectedAdminId}>
                    {isLoading ? 'Bezig met laden...' : 'Aanmelden'}
                </button>
            </div>
        </div>
    );
};

const ProgressBar = ({ percent }: { percent: number }) => (
    <div className="progress-cell">
        <div className="progress-bar-container">
            <div className="progress-bar-fill" style={{ width: `${percent}%` }}></div>
        </div>
        <span className="progress-text">{Math.round(percent)}%</span>
    </div>
);

const TaskCard = ({ task, onToggle, isTemplate = false, onDelete, canEdit = true, departments }: { 
    task: Task, onToggle: (id: string) => void, isTemplate?: boolean, onDelete?: (id: string) => void, canEdit?: boolean, departments: Department[], key?: React.Key
}) => {
    const dept = departments.find(d => d.id === task.dienst);
    return (
        <div className={`task-card ${task.isCompleted ? 'completed' : ''} ${!canEdit && !isTemplate ? 'read-only' : ''}`}>
            <div className="task-header">
                <div className="task-main">
                    {!isTemplate && (
                        <input type="checkbox" checked={task.isCompleted} onChange={() => onToggle(task.id)} disabled={!canEdit} />
                    )}
                    <div className="task-content">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                            <h3>{task.title}</h3>
                            {!canEdit && !isTemplate && <span style={{ fontSize: '10px', background: 'var(--border)', padding: '2px 6px', borderRadius: '10px', color: 'var(--text-muted)' }}>Alleen lezen</span>}
                        </div>
                        {task.description && <p>{task.description}</p>}
                    </div>
                </div>
                {isTemplate && canEdit && <button className="delete-btn" onClick={() => onDelete?.(task.id)}>Verwijder</button>}
            </div>
            <div className="task-footer">
                <div className="tags">
                    <span className="tag dienst">{dept?.name || 'Onbekende Dienst'}</span>
                    <span className="tag category">{task.category}</span>
                    {task.applicableReasons && task.applicableReasons.length > 0 && (
                        <span className="tag scenario" style={{ background: 'var(--warning)', color: '#000' }}>
                            {task.applicableReasons.join(', ')}
                        </span>
                    )}
                </div>
                {task.isCompleted && (
                    <div className="completion-info">Voltooid door <strong>{task.completedBy}</strong> op {task.completedAt}</div>
                )}
            </div>
        </div>
    );
};

const App = () => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('onboarding_v11_state');
        if (saved) return JSON.parse(saved);
        return {
            user: null,
            departments: [
                { id: 'it-dept', name: 'IT' },
                { id: 'lik-dept', name: 'LIK' },
                { id: 'log-dept', name: 'Logistiek' }
            ],
            onboardingReasons: ['Nieuwe Medewerker', 'Terugkeer uit Verlof', 'Interne Transfer'],
            offboardingReasons: ['Ontslag', 'Langdurig Verlof', 'Pensionering', 'Overlijden'],
            templateTasks: INITIAL_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            offboardingTemplateTasks: INITIAL_OFFBOARDING_TASKS.map(t => ({ ...t, dienst: t.dienst === 'IT' ? 'it-dept' : t.dienst === 'LIK' ? 'lik-dept' : 'log-dept' })),
            employees: [],
            admins: [
                { id: '1', name: 'Super Admin', email: 'it@org.be', role: 'SuperUser', dienstId: 'it-dept' }
            ],
            view: 'employees',
            selectedEmployeeId: null,
            filterDienstId: 'All',
            filterCategory: 'All',
            theme: 'light',
            employeeSearchQuery: '',
            showOnlyIncomplete: false,
            deptSearchQuery: '',
            adminSearchQuery: ''
        };
    });

    const [isEmpModalOpen, setIsEmpModalOpen] = useState(false);
    const [empModalStatus, setEmpModalStatus] = useState<EmployeeStatus>('onboarding');
    const [isOffboardTriggerModalOpen, setIsOffboardTriggerModalOpen] = useState<string | null>(null);
    const [isAddAdminModalOpen, setIsAddAdminModalOpen] = useState(false);
    const [isAddDeptModalOpen, setIsAddDeptModalOpen] = useState(false);
    const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

    const [confirmDeleteEmp, setConfirmDeleteEmp] = useState<string | null>(null);
    const [confirmDeleteDept, setConfirmDeleteDept] = useState<string | null>(null);

    useEffect(() => {
        localStorage.setItem('onboarding_v11_state', JSON.stringify(state));
    }, [state]);

    const handleLogin = (user: User) => setState(prev => ({ ...prev, user }));
    const handleLogout = () => setState(prev => ({ ...prev, user: null }));
    const toggleTheme = () => setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));

    const accessibleEmployees = useMemo(() => {
        if (!state.user) return [];
        const isOffboardingView = state.view === 'offboarding';
        let filtered = state.employees.filter(e => isOffboardingView ? e.status === 'offboarding' : e.status === 'onboarding');

        if (state.employeeSearchQuery) {
            const query = state.employeeSearchQuery.toLowerCase();
            filtered = filtered.filter(e => e.name.toLowerCase().includes(query));
        }

        if (state.user.role === 'SuperUser') return filtered;
        return filtered.filter(e => e.departmentId === state.user?.dienstId);
    }, [state.employees, state.user, state.view, state.employeeSearchQuery]);

    const selectedEmployee = useMemo(() => 
        state.employees.find(e => e.id === state.selectedEmployeeId),
    [state.employees, state.selectedEmployeeId]);

    const filteredTasks = useMemo(() => {
        if (!selectedEmployee || !state.user) return [];
        const currentTasks = selectedEmployee.status === 'offboarding' ? selectedEmployee.offboardingTasks : selectedEmployee.tasks;

        return currentTasks.filter(t => {
            const dienstMatch = state.filterDienstId === 'All' || t.dienst === state.filterDienstId;
            const catMatch = state.filterCategory === 'All' || t.category === state.filterCategory;
            const incompleteMatch = !state.showOnlyIncomplete || !t.isCompleted;
            return dienstMatch && catMatch && incompleteMatch;
        });
    }, [selectedEmployee, state.filterDienstId, state.filterCategory, state.user, state.showOnlyIncomplete]);

    const createEmployee = (name: string, departmentId: string, status: EmployeeStatus, reason: string) => {
        const baseTasks = status === 'onboarding' ? state.templateTasks : state.offboardingTemplateTasks;
        const filteredInitialTasks = baseTasks.filter(t => 
            !t.applicableReasons || t.applicableReasons.length === 0 || t.applicableReasons.includes(reason)
        ).map(t => ({ ...t, id: generateId(), isCompleted: false }));

        const newEmployee: Employee = {
            id: generateId(),
            name,
            departmentId,
            startDate: new Date().toLocaleDateString('nl-BE'),
            status,
            reason,
            tasks: status === 'onboarding' ? filteredInitialTasks : [],
            offboardingTasks: status === 'offboarding' ? filteredInitialTasks : []
        };
        setState(prev => ({ ...prev, employees: [newEmployee, ...prev.employees], view: status === 'onboarding' ? 'employees' : 'offboarding' }));
        setIsEmpModalOpen(false);
    };

    const startOffboarding = (id: string, reason: string) => {
        setState(prev => ({
            ...prev,
            employees: prev.employees.map(e => {
                if (e.id === id) {
                    const filteredTasks = prev.offboardingTemplateTasks.filter(t => 
                        !t.applicableReasons || t.applicableReasons.length === 0 || t.applicableReasons.includes(reason)
                    ).map(t => ({ ...t, id: generateId(), isCompleted: false }));

                    return {
                        ...e,
                        status: 'offboarding',
                        reason,
                        offboardingTasks: filteredTasks
                    };
                }
                return e;
            }),
            view: 'offboarding'
        }));
        setIsOffboardTriggerModalOpen(null);
    };

    const deleteEmployee = (id: string) => {
        setState(prev => ({ ...prev, employees: prev.employees.filter(e => e.id !== id) }));
    };

    const toggleEmployeeTask = (taskId: string) => {
        if (!state.selectedEmployeeId || !state.user) return;

        setState(prev => {
            const empIndex = prev.employees.findIndex(e => e.id === prev.selectedEmployeeId);
            if (empIndex === -1) return prev;

            const emp = prev.employees[empIndex];
            const taskType = emp.status === 'offboarding' ? 'offboardingTasks' : 'tasks';
            const task = emp[taskType].find(t => t.id === taskId);

            const isAuthorized = prev.user?.role === 'SuperUser' || task?.dienst === prev.user?.dienstId;
            if (!isAuthorized) return prev;

            return {
                ...prev,
                employees: prev.employees.map((e, idx) => {
                    if (idx === empIndex) {
                        return {
                            ...e,
                            [taskType]: e[taskType].map(t => {
                                if (t.id === taskId) {
                                    const nextStatus = !t.isCompleted;
                                    return {
                                        ...t,
                                        isCompleted: nextStatus,
                                        completedBy: nextStatus ? prev.user?.name : undefined,
                                        completedAt: nextStatus ? new Date().toLocaleString('nl-BE') : undefined
                                    };
                                }
                                return t;
                            })
                        };
                    }
                    return e;
                })
            };
        });
    };

    const addReason = (type: 'on' | 'off', reason: string) => {
        const key = type === 'on' ? 'onboardingReasons' : 'offboardingReasons';
        if (state[key].includes(reason)) return;
        setState(p => ({ ...p, [key]: [...p[key], reason] }));
    };

    const deleteReason = (type: 'on' | 'off', reason: string) => {
        const key = type === 'on' ? 'onboardingReasons' : 'offboardingReasons';
        setState(p => ({ ...p, [key]: p[key].filter(r => r !== reason) }));
    };

    if (!state.user) {
        return <LoginScreen onLogin={handleLogin} admins={state.admins} departments={state.departments} />;
    }

    return (
        <div className={`app-container ${state.theme}`}>
            <Navbar 
                user={state.user} 
                onLogout={handleLogout} 
                setView={(v) => setState(p => ({ ...p, view: v, selectedEmployeeId: null, employeeSearchQuery: '' }))} 
                currentView={state.view} 
                theme={state.theme}
                onToggleTheme={toggleTheme}
            />

            <main className="main-content">
                {(state.view === 'employees' || state.view === 'offboarding') && (
                    <div className="employees-view">
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <h1>{state.view === 'employees' ? 'Medewerkers Onboarding' : 'Medewerkers Offboarding'}</h1>
                                <div style={{ display: 'flex', gap: '12px' }}>
                                    <input 
                                        type="text" 
                                        placeholder="Zoek medewerker..." 
                                        className="search-input"
                                        value={state.employeeSearchQuery}
                                        onChange={(e) => setState(p => ({ ...p, employeeSearchQuery: e.target.value }))}
                                        style={{ padding: '8px 12px', borderRadius: '4px', border: '1px solid var(--border)', background: 'var(--input-bg)', color: 'var(--text)' }}
                                    />
                                    <button className="primary-action-btn" onClick={() => { setEmpModalStatus(state.view === 'employees' ? 'onboarding' : 'offboarding'); setIsEmpModalOpen(true); }}>
                                        + Nieuwe Medewerker
                                    </button>
                                </div>
                            </div>
                        </header>
                        <div className="employee-list-container">
                            <table className="employee-table">
                                <thead>
                                    <tr>
                                        <th>Naam</th><th>Scenario</th><th>Dienst</th><th>Voortgang</th><th style={{ textAlign: 'right' }}>Acties</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {accessibleEmployees.map(emp => {
                                        const currentTasks = emp.status === 'offboarding' ? emp.offboardingTasks : emp.tasks;
                                        const completed = currentTasks.filter(t => t.isCompleted).length;
                                        const total = currentTasks.length;
                                        const percent = total > 0 ? (completed / total) * 100 : 0;
                                        const dept = state.departments.find(d => d.id === emp.departmentId);

                                        return (
                                            <tr key={emp.id} className="employee-row" onClick={() => setState(p => ({ ...p, view: 'checklist', selectedEmployeeId: emp.id }))}>
                                                <td><span className="emp-name-cell">{emp.name}</span></td>
                                                <td><span className="tag scenario" style={{ opacity: 0.8, fontSize: '10px' }}>{emp.reason}</span></td>
                                                <td><span className="emp-dept-badge">{dept?.name || 'SuperUser'}</span></td>
                                                <td><ProgressBar percent={percent} /></td>
                                                <td style={{ textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                                    <button className="icon-btn edit" onClick={() => setEditingEmployee(emp)}>✎</button>
                                                    {emp.status === 'onboarding' && (
                                                        <button className="icon-btn offboard" onClick={() => setIsOffboardTriggerModalOpen(emp.id)}>Offboarden</button>
                                                    )}
                                                    <button className="icon-btn delete" onClick={() => setConfirmDeleteEmp(emp.id)}>🗑</button>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'checklist' && selectedEmployee && (
                    <div className="checklist-view">
                        <button className="back-link" onClick={() => setState(p => ({ ...p, view: selectedEmployee.status === 'offboarding' ? 'offboarding' : 'employees', selectedEmployeeId: null }))}>← Terug naar overzicht</button>
                        <header className="dashboard-header">
                            <div className="header-flex">
                                <div>
                                    <h1>Checklist: {selectedEmployee.name}</h1>
                                    <p style={{ margin: '4px 0 0', color: 'var(--text-muted)', fontSize: '14px' }}>Scenario: <strong>{selectedEmployee.reason}</strong></p>
                                </div>
                                <div className="incomplete-toggle">
                                    <input type="checkbox" id="incompleteOnly" checked={state.showOnlyIncomplete} onChange={(e) => setState(p => ({ ...p, showOnlyIncomplete: e.target.checked }))} />
                                    <label htmlFor="incompleteOnly">Toon alleen onvoltooid</label>
                                </div>
                            </div>
                        </header>
                        <div className="task-grid">
                            {filteredTasks.map(task => {
                                const canEdit = state.user?.role === 'SuperUser' || task.dienst === state.user?.dienstId;
                                return <TaskCard key={task.id} task={task} onToggle={toggleEmployeeTask} departments={state.departments} canEdit={canEdit} />;
                            })}
                        </div>
                    </div>
                )}

                {(state.view === 'template_onboarding' || state.view === 'template_offboarding') && (
                    <div className="template-manager">
                        <h1>{state.view === 'template_onboarding' ? 'Onboarding Template' : 'Offboarding Template'}</h1>
                        <div className="add-task-form">
                            <form onSubmit={(e) => {
                                e.preventDefault();
                                const form = e.target as any;
                                const reasons = Array.from(form.applicableReasons.selectedOptions).map((o: any) => o.value).filter(v => v !== 'Alle');
                                const newTask: Task = {
                                    id: generateId(), title: form.title.value, description: form.desc.value,
                                    dienst: form.dienstId.value, category: form.cat.value, isCompleted: false,
                                    applicableReasons: reasons
                                };
                                const listKey = state.view === 'template_onboarding' ? 'templateTasks' : 'offboardingTemplateTasks';
                                setState(prev => ({ ...prev, [listKey]: [...prev[listKey], newTask] }));
                                form.reset();
                            }}>
                                <div className="form-row">
                                    <input name="title" placeholder="Taak Titel" required /><input name="desc" placeholder="Beschrijving" />
                                </div>
                                <div className="form-row">
                                    <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                                    <select name="cat"><option value="Account">Account</option><option value="Hardware">Hardware</option><option value="Software">Software</option><option value="Toegang">Toegang</option></select>
                                    <select name="applicableReasons" multiple style={{ height: '60px' }}>
                                        <option value="Alle">Geldt voor iedereen</option>
                                        {(state.view === 'template_onboarding' ? state.onboardingReasons : state.offboardingReasons).map(r => <option key={r} value={r}>{r}</option>)}
                                    </select>
                                    <button type="submit" className="primary-action-btn">Voeg toe aan template</button>
                                </div>
                                <small style={{ color: 'var(--text-muted)' }}>Houd Ctrl (of Cmd) ingedrukt om meerdere scenario's te selecteren.</small>
                            </form>
                        </div>
                        <div className="task-grid">
                            {(state.view === 'template_onboarding' ? state.templateTasks : state.offboardingTemplateTasks).map(task => (
                                <TaskCard key={task.id} task={task} isTemplate onToggle={() => {}} onDelete={(id) => {
                                    const key = state.view === 'template_onboarding' ? 'templateTasks' : 'offboardingTemplateTasks';
                                    setState(p => ({ ...p, [key]: p[key].filter(t => t.id !== id) }));
                                }} departments={state.departments} />
                            ))}
                        </div>
                    </div>
                )}

                {state.view === 'reason_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Scenario's (Redenen)</h1>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '32px', marginTop: '24px' }}>
                            {/* Onboarding Reasons */}
                            <div className="employee-list-container">
                                <div style={{ padding: '16px', borderBottom: '1px solid var(--border)', background: 'var(--bg)' }}>
                                    <strong>Onboarding Scenario's</strong>
                                </div>
                                <div style={{ padding: '16px' }}>
                                    <form onSubmit={(e) => { e.preventDefault(); const input = (e.target as any).reason; addReason('on', input.value); input.value = ''; }} style={{ display: 'flex', gap: '8px' }}>
                                        <input name="reason" placeholder="Nieuw scenario..." style={{ flex: 1, padding: '8px', borderRadius: '4px', border: '1px solid var(--border)' }} required />
                                        <button className="primary-action-btn" style={{ padding: '8px 16px' }}>+</button>
                                    </form>
                                </div>
                                <table className="employee-table">
                                    <tbody>
                                        {state.onboardingReasons.map(r => (
                                            <tr key={r}><td>{r}</td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => deleteReason('on', r)}>🗑</button></td></tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>

                            {/* Offboarding Reasons */}
                            <div className="employee-list-container">
                                <div style={{ padding: '16px', borderBottom: '1px solid var(--border)', background: 'var(--bg)' }}>
                                    <strong>Offboarding Scenario's</strong>
                                </div>
                                <div style={{ padding: '16px' }}>
                                    <form onSubmit={(e) => { e.preventDefault(); const input = (e.target as any).reason; addReason('off', input.value); input.value = ''; }} style={{ display: 'flex', gap: '8px' }}>
                                        <input name="reason" placeholder="Nieuw scenario..." style={{ flex: 1, padding: '8px', borderRadius: '4px', border: '1px solid var(--border)' }} required />
                                        <button className="primary-action-btn" style={{ padding: '8px 16px' }}>+</button>
                                    </form>
                                </div>
                                <table className="employee-table">
                                    <tbody>
                                        {state.offboardingReasons.map(r => (
                                            <tr key={r}><td>{r}</td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => deleteReason('off', r)}>🗑</button></td></tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                )}

                {state.view === 'dept_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Diensten</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddDeptModalOpen(true)}>+ Nieuwe Dienst</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Dienstnaam</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.departments.map(d => (
                                        <tr key={d.id}><td><strong>{d.name}</strong></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setConfirmDeleteDept(d.id)} title="Dienst verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {state.view === 'admin_beheer' && state.user.role === 'SuperUser' && (
                    <div className="admin-beheer">
                        <h1>Beheer Admins</h1>
                        <button className="primary-action-btn" onClick={() => setIsAddAdminModalOpen(true)}>+ Nieuwe Admin</button>
                        <div className="employee-list-container" style={{ marginTop: '20px' }}>
                            <table className="employee-table">
                                <thead><tr><th>Naam</th><th>Email</th><th>Gekoppelde Dienst</th><th style={{ textAlign: 'right' }}>Acties</th></tr></thead>
                                <tbody>
                                    {state.admins.map(a => (
                                        <tr key={a.id}><td><strong>{a.name}</strong></td><td>{a.email}</td><td><span className="emp-dept-badge">{state.departments.find(d => d.id === a.dienstId)?.name || 'Geen'}</span></td><td style={{ textAlign: 'right' }}><button className="icon-btn delete" onClick={() => setState(p => ({ ...p, admins: p.admins.filter(ad => ad.id !== a.id) }))} title="Admin verwijderen">🗑</button></td></tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}
            </main>

            {/* Reden-selectie voor Offboarding */}
            <Modal isOpen={!!isOffboardTriggerModalOpen} onClose={() => setIsOffboardTriggerModalOpen(null)} title="Offboarding Starten">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    startOffboarding(isOffboardTriggerModalOpen!, (e.target as any).reason.value);
                }}>
                    <p>Waarom verlaat deze medewerker de organisatie?</p>
                    <div className="form-group">
                        <label>Reden van vertrek</label>
                        <select name="reason">
                            {state.offboardingReasons.map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Start Offboarding Checklist</button></div>
                </form>
            </Modal>

            <Modal isOpen={isEmpModalOpen} onClose={() => setIsEmpModalOpen(false)} title={`Medewerker Toevoegen (${empModalStatus})`}>
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const f = e.target as any;
                    createEmployee(f.name.value, f.deptId.value, empModalStatus, f.reason.value);
                }}>
                    <div className="form-group"><label>Volledige Naam</label><input name="name" required /></div>
                    <div className="form-group">
                        <label>Dienst</label>
                        <select name="deptId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Reden / Scenario</label>
                        <select name="reason">
                            {(empModalStatus === 'onboarding' ? state.onboardingReasons : state.offboardingReasons).map(r => <option key={r} value={r}>{r}</option>)}
                        </select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Aanmaken</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddDeptModalOpen} onClose={() => setIsAddDeptModalOpen(false)} title="Nieuwe Dienst Toevoegen">
                <form className="add-emp-form" onSubmit={(e) => { e.preventDefault(); const newDept: Department = { id: generateId(), name: (e.target as any).name.value }; setState(p => ({ ...p, departments: [...p.departments, newDept] })); setIsAddDeptModalOpen(false); }}>
                    <div className="form-group"><label>Dienst Naam</label><input name="name" placeholder="Bijv. Marketing, HR, etc." required /></div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Toevoegen</button></div>
                </form>
            </Modal>

            <Modal isOpen={isAddAdminModalOpen} onClose={() => setIsAddAdminModalOpen(false)} title="Nieuwe Administrator">
                <form className="add-emp-form" onSubmit={(e) => {
                    e.preventDefault();
                    const form = e.target as any;
                    const newAdmin: User = { id: generateId(), name: form.name.value, email: form.email.value, role: form.role.value, dienstId: form.dienstId.value };
                    setState(p => ({ ...p, admins: [...p.admins, newAdmin] }));
                    setIsAddAdminModalOpen(false);
                }}>
                    <div className="form-group"><label>Naam</label><input name="name" required /></div>
                    <div className="form-group"><label>Email</label><input name="email" type="email" required /></div>
                    <div className="form-group">
                        <label>Gekoppelde Dienst</label>
                        <select name="dienstId">{state.departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select>
                    </div>
                    <div className="form-group">
                        <label>Rechtenniveau</label>
                        <select name="role"><option value="Admin">Afdeling-Admin</option><option value="SuperUser">SuperUser (IT/Hoofdbeheer)</option></select>
                    </div>
                    <div className="modal-footer"><button type="submit" className="primary-action-btn">Admin Opslaan</button></div>
                </form>
            </Modal>

            <ConfirmationModal 
                isOpen={!!confirmDeleteEmp}
                onClose={() => setConfirmDeleteEmp(null)}
                onConfirm={() => confirmDeleteEmp && deleteEmployee(confirmDeleteEmp)}
                title="Verwijderen"
                message="Weet u zeker dat u deze medewerker wilt verwijderen?"
            />
        </div>
    );
};

const root = ReactDOM.createRoot(document.getElementById('root')!);
root.render(<App />);

:root {
