    --text: #323130;
    --text-muted: #605e5d;
    --border: #edebe9;
    --success: #107c10;
    --danger: #d13438;
    --warning: #ffb900;
    --shadow: 0 8px 16px rgba(0,0,0,0.1), 0 2px 4px rgba(0,0,0,0.05);
